#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, N, sizeof(int), compare);
        int *res = (int*)malloc(N * sizeof(int));
        int idx = 0;
        for (int i = 0; i < N; i++) {
            if (i % K == 0) {
                idx = 0;
            }
            int j;
            for (j = idx; j < N; j++) {
                if (j % K != i % K || arr[j] != arr[i]) {
                    res[i] = arr[j];
                    arr[j] = arr[idx];
                    idx++;
                    break;
                }
            }
            if (j == N) {
                printf("-1\n");
                free(arr);
                free(res);
                break;
            }
        }
        if (i == N) {
            for (int i = 0; i < N; i++) {
                printf("%d ", res[i]);
            }
            printf("\n");
            free(arr);
            free(res);
        }
    }
    return 0;
}

