import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            Arrays.sort(arr);
            int[] res = new int[N];
            int idx = 0;
            for (int i = 0; i < N; i++) {
                if (i % K == 0) {
                    idx = 0;
                }
                int j;
                for (j = idx; j < N; j++) {
                    if (j % K != i % K || arr[j] != arr[i]) {
                        res[i] = arr[j];
                        arr[j] = arr[idx];
                        idx++;
                        break;
                    }
                }
                if (j == N) {
                    System.out.println(-1);
                    break;
                }
            }
            if (i == N) {
                for (int i = 0; i < N; i++) {
                    System.out.print(res[i] + " ");
                }
                System.out.println();
            }
        }
    }
}

