const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextLine() {
    return lines[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextInts() {
    return nextLine().split(' ').map(Number);
}

let T = nextInt();
while (T-- > 0) {
    let [N, K] = nextInts();
    let arr = nextInts();
    arr.sort((a, b) => a - b);
    let res = new Array(N);
    let id = 0;
    for (let i = 0; i < N; i++) {
        if (i % K === 0) {
            id = 0;
        }
        let j = id;
        while (j < N) {
            if (j % K !== i % K || arr[j] !== arr[i]) {
                res[i] = arr[j];
                [arr[j], arr[id]] = [arr[id], arr[j]];
                id++;
                break;
            }
            j++;
        }
        if (j === N) {
            console.log(-1);
            break;
        }
    }
    if (i === N) {
        console.log(res.join(' '));
    }
}

